    for (let i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + strategy[i] * prices[i];
    }

    // Precompute the sum of prices for the first half (0) and second half (1) of the window
    // For the first half (0), the contribution is 0 * prices[i] - strategy[i] * prices[i] = -strategy[i] * prices[i]
    // For the second half (1), the contribution is 1 * prices[i] - strategy[i] * prices[i] = (1 - strategy[i]) * prices[i]
    // So the total delta for a window [i, i + k - 1] is:
    // sum_{j=i}^{i + k/2 - 1} (-strategy[j] * prices[j]) + sum_{j=i + k/2}^{i + k - 1} ((1 - strategy[j]) * prices[j])

    // Precompute the delta for each possible window
    let maxDelta = 0;
    // Compute the delta for the first possible window [0, k-1]
    let delta = 0;
    for (let i = 0; i < halfK; i++) {
        delta += -strategy[i] * prices[i];
    }
    for (let i = halfK; i < k; i++) {
        delta += (1 - strategy[i]) * prices[i];
    }
    maxDelta = delta;

    // Slide the window to compute delta for other windows
    for (let i = 1; i <= n - k; i++) {
        // Remove the contribution of the leftmost element of the previous window
        const leftOut = i - 1;
        if (leftOut < leftOut + halfK) {
            delta -= -strategy[leftOut] * prices[leftOut];
        } else {
            delta -= (1 - strategy[leftOut]) * prices[leftOut];
        }

        // Add the contribution of the new rightmost element
        const rightIn = i + k - 1;
        if (rightIn < i + halfK) {
            delta += -strategy[rightIn] * prices[rightIn];
        } else {
            delta += (1 - strategy[rightIn]) * prices[rightIn];
        }

        // Also need to adjust the middle elements if the window moves and halfK elements change
        // But sliding window approach already handles this by removing left and adding right

        if (delta > maxDelta) {
            maxDelta = delta;
        }
    }

    maxProfit = originalProfit + maxDelta;
    return maxProfit;
}
